const item = $input.first().json;
const query = item.query || {};
const expected = $env.WHATSAPP_WEBHOOK_VERIFY_TOKEN || $env.WHATSAPP_VERIFY_TOKEN || $env.IG_WEBHOOK_VERIFY_TOKEN || '';
const mode = query['hub.mode'] || query.hub_mode || '';
const token = query['hub.verify_token'] || query.hub_verify_token || '';
const challenge = query['hub.challenge'] || query.hub_challenge || '';
const verified = mode === 'subscribe' && !!challenge && !!expected && token === expected;

return [{
  json: {
    verified,
    challenge: verified ? String(challenge) : '',
    status_code: verified ? 200 : 403,
    error: verified ? null : 'invalid_whatsapp_verify_token'
  }
}];

const item = $input.first().json;
const body = item.body || item;
const tenantId = $env.DEFAULT_TENANT_ID || $env.TENANT_ID || 'default';
const out = [];

function textFromMessage(message) {
  if (!message) return '';
  if (message.text?.body) return String(message.text.body);
  if (message.button?.text) return String(message.button.text);
  if (message.interactive?.button_reply?.title) return String(message.interactive.button_reply.title);
  if (message.interactive?.list_reply?.title) return String(message.interactive.list_reply.title);
  if (message.image?.caption) return String(message.image.caption);
  if (message.document?.caption) return String(message.document.caption);
  if (message.audio) return '[Audio message received. Ask the customer to send text until transcription is enabled.]';
  if (message.image) return '[Image message received. Ask a concise clarifying question if the image content is required.]';
  if (message.document) return '[Document received. Ask what part of the document they want help with until document ingestion is enabled.]';
  return '';
}

for (const entry of body.entry || []) {
  for (const change of entry.changes || []) {
    const value = change.value || {};
    const contactsByWaId = {};
    for (const contact of value.contacts || []) {
      if (contact.wa_id) contactsByWaId[contact.wa_id] = contact;
    }

    for (const message of value.messages || []) {
      const from = message.from || '';
      const text = textFromMessage(message).trim();
      if (!from || !text) continue;

      const contact = contactsByWaId[from] || {};
      const displayName = contact.profile?.name || from;
      const phoneNumberId = value.metadata?.phone_number_id || $env.WHATSAPP_PHONE_NUMBER_ID || $env.WA_PHONE_NUMBER_ID || '';

      out.push({
        json: {
          tenant_id: tenantId,
          channel: 'whatsapp',
          thread_id: `whatsapp:${from}`,
          sender_id: from,
          sender_display_name: displayName,
          sender_username: from,
          message_text: text,
          message_id: message.id || `${Date.now()}-${from}`,
          message_type: message.type || 'unknown',
          phone_number_id: phoneNumberId,
          to: from,
          raw_event: {
            object: body.object || null,
            entry_id: entry.id || null,
            field: change.field || null,
            message,
            contact,
            metadata: value.metadata || null
          }
        }
      });
    }
  }
}

return out;

const core = $input.first().json || {};
let source = {};
try { source = $('Normalize WhatsApp Message').first().json || {}; } catch (error) { source = {}; }

const status = core.status || 'unknown';
const response = String(core.response || core.answer || '').trim();
const shouldStaySilent = status === 'escalated_silent' || status === 'ignored' || core.silence === true || !response;
if (shouldStaySilent) return [];

const maxLen = 3900;
const body = response.length > maxLen ? response.slice(0, maxLen - 20).trimEnd() + '…' : response;
const phoneNumberId = source.phone_number_id || $env.WHATSAPP_PHONE_NUMBER_ID || $env.WA_PHONE_NUMBER_ID || '';
const accessTokenPresent = !!($env.WHATSAPP_ACCESS_TOKEN || $env.WA_ACCESS_TOKEN);

return [{
  json: {
    channel: 'whatsapp',
    to: source.to || source.sender_id,
    phone_number_id: phoneNumberId,
    body,
    core_status: status,
    confidence: core.confidence ?? null,
    requires_handoff: !!core.requires_handoff,
    access_token_present: accessTokenPresent
  }
}];
